  1	import * as React from 'react';
  2	import {
  3	  BUCKET_BOOKMARKS_USER_SETTINGS_KEY,
  4	  getBucketOverviewBaseRoute,
  5	} from '@odf/core/constants';
  6	import { EmptyBucketResponse } from '@odf/core/modals/s3-browser/delete-and-empty-bucket/EmptyBucketModal';
  7	import {
  8	  LazyDeleteBucketModal,
  9	  LazyEmptyBucketModal,
 10	} from '@odf/core/modals/s3-browser/delete-and-empty-bucket/lazy-delete-and-empty-bucket';
 11	import { BucketCrFormat, S3ProviderType } from '@odf/core/types';
 12	import { Timestamp } from '@odf/shared/details-page/timestamp';
 13	import { EmptyPage } from '@odf/shared/empty-state-page';
 14	import { useUserSettingsLocalStorage } from '@odf/shared/hooks/useUserSettingsLocalStorage';
 15	import { S3Commands } from '@odf/shared/s3';
 16	import {
 17	  ComposableTable,
 18	  RowComponentType,
 19	} from '@odf/shared/table/composable-table';
 20	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 21	import { sortRows } from '@odf/shared/utils';
 22	import { useModal } from '@openshift-console/dynamic-plugin-sdk';
 23	import { LaunchModal } from '@openshift-console/dynamic-plugin-sdk/lib/app/modal-support/ModalProvider';
 24	import { TFunction } from 'react-i18next';
 25	import { Link } from 'react-router-dom-v5-compat';
 26	import { Bullseye, Label } from '@patternfly/react-core';
 27	import { UserIcon } from '@patternfly/react-icons';
 28	import {
 29	  ActionsColumn,
 30	  IAction,
 31	  TableVariant,
 32	  Td,
 33	  Tr,
 34	} from '@patternfly/react-table';
 35	import { getProviderLabel } from '../../../utils';
 36	import { S3Context } from '../s3-context';
 37	
 38	const getRowActions = (
 39	  t: TFunction<string>,
 40	  launcher: LaunchModal,
 41	  bucketName: string,
 42	  s3Client: S3Commands,
 43	  refreshTokens: () => void,
 44	  setEmptyBucketResponse: React.Dispatch<
 45	    React.SetStateAction<EmptyBucketResponse>
 46	  >
 47	): IAction[] => [
 48	  {
 49	    title: (
 50	      <>
 51	        {t('Empty bucket')}
 52	        <p className="text-muted pf-v6-u-font-size-xs">
 53	          {t('Erase the contents of your bucket')}
 54	        </p>
 55	      </>
 56	    ),
 57	    onClick: () =>
 58	      launcher(LazyEmptyBucketModal, {
 59	        isOpen: true,
 60	        extraProps: {
 61	          bucketName,
 62	          s3Client,
 63	          refreshTokens,
 64	          setEmptyBucketResponse,
 65	        },
 66	      }),
 67	  },
 68	  {
 69	    title: t('Delete bucket'),
 70	    onClick: () =>
 71	      launcher(LazyDeleteBucketModal, {
 72	        isOpen: true,
 73	        extraProps: {
 74	          bucketName,
 75	          s3Client,
 76	          launcher,
 77	          refreshTokens,
 78	          setEmptyBucketResponse,
 79	        },
 80	      }),
 81	  },
 82	];
 83	
 84	const getColumnNames = (t: TFunction<string>) => [
 85	  '', // favoritable,
 86	  t('Name'),
 87	  t('Storage endpoint'),
 88	  t('Create on'),
 89	  t('Owner'),
 90	  '', // action kebab
 91	];
 92	
 93	const getHeaderColumns = (t: TFunction<string>, favorites: string[]) => {
 94	  const columnNames = getColumnNames(t);
 95	  return [
 96	    {
 97	      columnName: columnNames[0],
 98	      sortFunction: (a, b, c) => sortRows(a, b, c, 'metadata.name', favorites),
 99	    },
100	    {
101	      columnName: columnNames[1],
102	      sortFunction: (a, b, c) => sortRows(a, b, c, 'metadata.name'),
103	    },
104	    {
105	      columnName: columnNames[2],
106	      thProps: {
107	        className: 'pf-v5-u-w-16-on-lg',
108	      },
109	    },
110	    {
111	      columnName: columnNames[3],
112	      sortFunction: (a, b, c) =>
113	        sortRows(a, b, c, 'metadata.creationTimestamp'),
114	      thProps: {
115	        className: 'pf-v5-u-w-16-on-lg',
116	      },
117	    },
118	    {
119	      columnName: columnNames[4],
120	      thProps: {
121	        className: 'pf-v5-u-w-16-on-lg',
122	      },
123	    },
124	    {
125	      columnName: columnNames[5],
126	    },
127	  ];
128	};
129	
130	const NoBucketMessage: React.FC = () => {
131	  const { t } = useCustomTranslation();
132	  return (
133	    <EmptyPage
134	      ButtonComponent={() => null}
135	      title={t('Create and manage your buckets')}
136	      isLoaded
137	      canAccess
138	    >
139	      {t(
140	        'Navigate through your buckets effortlessly. View the contents of your S3-managed and Openshift-managed buckets, making it easy to locate and inspect objects.'
141	      )}
142	    </EmptyPage>
143	  );
144	};
145	
146	const EmptyRowMessage: React.FC = () => {
147	  const { t } = useCustomTranslation();
148	  return <Bullseye className="pf-v6-u-mt-xl">{t('No buckets found')}</Bullseye>;
149	};
150	
151	const BucketsTableRow: React.FC<RowComponentType<BucketCrFormat>> = ({
152	  row: bucket,
153	  rowIndex,
154	  extraProps,
155	}) => {
156	  const { t } = useCustomTranslation();
157	  const columnNames = getColumnNames(t);
158	  const {
159	    apiResponse: { owner },
160	    metadata: { name, creationTimestamp },
161	  } = bucket;
162	  const {
163	    favorites,
164	    setFavorites,
165	    triggerRefresh,
166	    setEmptyBucketResponse,
167	    launcher,
168	  }: RowExtraPropsType = extraProps;
169	
170	  const { s3Client } = React.useContext(S3Context);
171	
172	  const onSetFavorite = (key, active) => {
173	    setFavorites((oldFavorites) => [
174	      ...oldFavorites.filter((oldFavorite) => oldFavorite !== key),
175	      ...(active ? [key] : []),
176	    ]);
177	  };
178	
179	  const providerType = s3Client.providerType as S3ProviderType;
180	
181	  return (
182	    <Tr key={rowIndex}>
183	      <Td
184	        dataLabel={columnNames[0]}
185	        favorites={{
186	          isFavorited: favorites.includes(name),
187	          onFavorite: (_event, isFavoriting) =>
188	            onSetFavorite(name, isFavoriting),
189	          rowIndex,
190	        }}
191	      />
192	      <Td dataLabel={columnNames[1]}>
193	        <Link to={`${getBucketOverviewBaseRoute(name, providerType)}/objects`}>
194	          {name}
195	        </Link>
196	      </Td>
197	      <Td dataLabel={columnNames[2]}>
198	        <Label color="gold">{getProviderLabel(providerType)}</Label>
199	      </Td>
200	      <Td dataLabel={columnNames[3]}>
201	        {<Timestamp timestamp={creationTimestamp} ignoreRelativeTime />}
202	      </Td>
203	      <Td dataLabel={columnNames[4]}>
204	        <UserIcon /> <span data-test="owner">{owner}</span>
205	      </Td>
206	      <Td dataLabel={columnNames[5]} isActionCell>
207	        <ActionsColumn
208	          items={getRowActions(
209	            t,
210	            launcher,
211	            name,
212	            s3Client,
213	            triggerRefresh,
214	            setEmptyBucketResponse
215	          )}
216	        />
217	      </Td>
218	    </Tr>
219	  );
220	};
221	
222	export const BucketsListTable: React.FC<BucketsListTableProps> = ({
223	  allBuckets,
224	  filteredBuckets,
225	  loaded,
226	  error,
227	  setEmptyBucketResponse,
228	  triggerRefresh,
229	}) => {
230	  const { t } = useCustomTranslation();
231	  const [favorites, setFavorites] = useUserSettingsLocalStorage<string[]>(
232	    BUCKET_BOOKMARKS_USER_SETTINGS_KEY,
233	    true,
234	    []
235	  );
236	  const launcher = useModal();
237	
238	  return (
239	    <ComposableTable
240	      rows={filteredBuckets}
241	      columns={getHeaderColumns(t, favorites)}
242	      RowComponent={BucketsTableRow}
243	      noDataMsg={NoBucketMessage}
244	      emptyRowMessage={EmptyRowMessage}
245	      unfilteredData={allBuckets as []}
246	      loaded={loaded}
247	      loadError={error}
248	      isFavorites={true}
249	      variant={TableVariant.compact}
250	      extraProps={{
251	        favorites,
252	        setFavorites,
253	        triggerRefresh,
254	        setEmptyBucketResponse,
255	        launcher,
256	      }}
257	    />
258	  );
259	};
260	
261	type BucketsListTableProps = {
262	  allBuckets: BucketCrFormat[];
263	  filteredBuckets: BucketCrFormat[];
264	  loaded: boolean;
265	  error: any;
266	  setEmptyBucketResponse: React.Dispatch<
267	    React.SetStateAction<EmptyBucketResponse>
268	  >;
269	  triggerRefresh: () => void;
270	};
271	
272	type RowExtraPropsType = {
273	  favorites: string[];
274	  setFavorites: React.Dispatch<React.SetStateAction<string[]>>;
275	  triggerRefresh: () => void;
276	  setEmptyBucketResponse: React.Dispatch<
277	    React.SetStateAction<EmptyBucketResponse>
278	  >;
279	  launcher: LaunchModal;
280	};

