 29	export const ComposableTable: ComposableTableProps = <
 30	  T extends K8sResourceCommon,
 31	>({
 32	  columns,
 33	  rows,
 34	  RowComponent,
 35	  extraProps,
 36	  loaded,
 37	  loadError,
 38	  unfilteredData,
 39	  noDataMsg,
 40	  emptyRowMessage,
 41	  variant,
 42	  isFavorites,
 43	}) => {
 44	  const {
 45	    onSort,
 46	    sortIndex: activeSortIndex,
 47	    sortDirection: activeSortDirection,
 48	    sortedData: sortedRows,
 49	  } = useSortList<T>(rows, columns, false);
 50	  const { t } = useCustomTranslation();
 51	
 52	  const getSortParams = (columnIndex: number): ThProps['sort'] => ({
 53	    ...(isFavorites ? { isFavorites: columnIndex === 0 } : {}),
 54	    sortBy: {
 55	      index: activeSortIndex,
 56	      direction: activeSortDirection,
 57	    },
 58	    onSort: onSort,
 59	    columnIndex,
 60	  });
 61	
 62	  return (
 63	    <StatusBox
 64	      loadError={loadError}
 65	      loaded={loaded}
 66	      data={sortedRows}
 67	      EmptyMsg={emptyRowMessage}
 68	      unfilteredData={unfilteredData}
 69	      NoDataEmptyMsg={noDataMsg}
 70	      skeleton={<div className="loading-skeleton--table pf-v6-u-mt-lg" />}
 71	    >
 72	      <Table
 73	        aria-label={t('Composable table')}
 74	        className="pf-v6-u-mt-md"
 75	        variant={variant}
 76	      >
 77	        <Thead>
 78	          <Tr>
 79	            {columns?.map((col, index) => (
 80	              <Th
 81	                {...(!!col?.thProps ? col.thProps : {})}
 82	                {...(!!col?.sortFunction ? { sort: getSortParams(index) } : {})}
 83	                key={col?.columnName}
 84	              >
 85	                {col?.columnName}
 86	              </Th>
 87	            ))}
 88	          </Tr>
 89	        </Thead>
 90	        <Tbody>
 91	          {sortedRows.map((row, rowIndex) => (
 92	            <RowComponent
 93	              row={row}
 94	              rowIndex={rowIndex}
 95	              extraProps={extraProps}
 96	            />
 97	          ))}
 98	        </Tbody>
 99	      </Table>
100	    </StatusBox>
101	  );
102	};
103	
104	// Omit ref to resolve incompatible issue
105	// sort is replaced by sortFunction
106	type TableThProps = Omit<ThProps, 'sort' | 'ref'>;
107	
108	export type TableProps<T extends K8sResourceCommon | unknown> = {
109	  rows: T[];
110	  columns: TableColumnProps[];
111	  RowComponent: React.ComponentType<RowComponentType<T>>;
112	  extraProps?: any;
113	  loaded: boolean;
114	  loadError?: any;
115	  unfilteredData?: [];
116	  noDataMsg?: React.FC;
117	  emptyRowMessage?: React.FC;
118	  variant?: TableVariant;
119	  isFavorites?: boolean;
120	};
121	
122	type ComposableTableProps = <T extends K8sResourceCommon>(
123	  props: React.PropsWithoutRef<TableProps<T>>
124	) => ReturnType<React.FC>;

